    int next_i = (i + 1) % N;

    long long required_prev = nums[prev_i] + 1;
    long long required_next = nums[next_i] + 1;

    long long target = max(required_prev, required_next);

    // Cost is max(0, target - current_value)
    long long cost = max(0LL, target - nums[i]);
    costs[i] = cost;
