// dp[i][j][0]: Min cost using first i+1 elements (0..i), selecting j peaks, and index i is NOT a peak.
// dp[i][j][1]: Min cost using first i+1 elements (0..i), selecting j peaks, and index i IS a peak.

// Size: N x (K+1) x 2. N <= 5000, K <= 5000. O(N*K) complexity, which is acceptable.

// Initialize DP table with a large value (infinity)
const long long INF = 1e18;
vector<vector<vector<long long>>> dp(N, vector<vector<long long>>(k + 1, vector<long long>(2, INF)));

// --- Case 1: Element 0 is NOT chosen ---
// We solve the DP on a line graph (indices 1 to N-1) assuming index 0 is excluded.
// This requires a separate DP run, or careful initialization.

// Let's simplify the cycle handling by running DP twice:
// 1. Assume 0 is NOT selected. Solve DP on 1...N-1.
// 2. Assume 0 IS selected. This forces 1 and N-1 NOT to be selected. Solve DP on 2...N-2.

// --- DP on a line segment [start, end] ---
auto solve_line = [&](int start_idx, int end_idx, long long forbidden_prev_cost, long long forbidden_next_cost) -> long long {
    if (start_idx > end_idx) {
        return 0; // Empty segment
    }

    // dp_line[i][j][state] for segment [start_idx, end_idx]
    // i is the index relative to start_idx (0 to end_idx - start_idx)
    int len = end_idx - start_idx + 1;
    vector<vector<vector<long long>>> dp_line(len, vector<vector<long long>>(k + 1, vector<long long>(2, INF)));

    // Base case: i = 0 (which is index start_idx)
    // If we select start_idx (state=1): cost is costs[start_idx]
    if (0 <= k) {
        dp_line[0][1][1] = costs[start_idx];
    }
    // If we don't select start_idx (state=0): cost is 0
    dp_line[0][0][0] = 0;

    for (int i = 1; i < len; ++i) {
        int current_idx = start_idx + i;

        // 1. Calculate dp_line[i][j][0] (current_idx NOT selected)
        for (int j = 0; j <= k; ++j) {
            // Previous could be selected or not selected
            dp_line[i][j][0] = min(dp_line[i-1][j][0], dp_line[i-1][j][1]);
        }

        // 2. Calculate dp_line[i][j][1] (current_idx IS selected)
        for (int j = 1; j <= k; ++j) {
            // Previous MUST NOT be selected
            if (dp_line[i-1][j-1][0] != INF) {
                dp_line[i][j][1] = dp_line[i-1][j-1][0] + costs[current_idx];
            }
        }
    }

    // The result for the line segment is the minimum cost to get exactly k peaks (or up to k, since we only need at least k)
    // Wait, we need EXACTLY k peaks in the DP state, because the constraints on the cycle are handled by the outer structure.

    long long min_cost = INF;
    for (int j = k; j <= k; ++j) { // We only care about exactly k for the line segment approach if we fix endpoints.
        min_cost = min(min_cost, dp_line[len-1][j][0]);
        min_cost = min(min_cost, dp_line[len-1][j][1]);
    }

    // Since we are looking for AT LEAST k, we should iterate j from k up to len.
    long long final_min_cost = INF;
    for (int j = k; j <= len; ++j) {
        final_min_cost = min(final_min_cost, dp_line[len-1][j][0]);
        final_min_cost = min(final_min_cost, dp_line[len-1][j][1]);
    }

    return final_min_cost;
