    // DP for the line segment [2, N-2]
    int start_idx = 2;
    int end_idx = N - 2;
    int required_peaks = k - 1;

    if (start_idx <= end_idx) {
        int len_line = end_idx - start_idx + 1;
        vector<vector<vector<long long>>> dp_line(len_line, vector<vector<long long>>(k + 1, vector<long long>(2, INF)));

        // Base case: i = 0 (index 2)
        if (0 <= k) {
            dp_line[0][1][1] = costs[2];
        }
        dp_line[0][0][0] = 0;

        for (int i = 1; i < len_line; ++i) {
            int current_idx = start_idx + i;

            // 1. Not selected
            for (int j = 0; j <= k; ++j) {
                dp_line[i][j][0] = min(dp_line[i-1][j][0], dp_line[i-1][j][1]);
            }

            // 2. Selected
            for (int j = 1; j <= k; ++j) {
                if (dp_line[i-1][j-1][0] != INF) {
                    dp_line[i][j][1] = dp_line[i-1][j-1][0] + costs[current_idx];
                }
            }
        }

        // Check for AT LEAST K-1 peaks in the line segment [2, N-2]
        long long line_cost = INF;
        for (int j = required_peaks; j <= len_line; ++j) {
            line_cost = min(line_cost, min(dp_line[len_line-1][j][0], dp_line[len_line-1][j][1]));
        }

        if (line_cost != INF) {
            overall_min_cost = min(overall_min_cost, line_cost + costs[0]);
        }
    } else if (required_peaks == 0) {
        // Segment is empty, cost is just costs[0]
        overall_min_cost = min(overall_min_cost, costs[0]);
    }
}


if (overall_min_cost == INF) {
    return -1;
